record.field:
for record in records:
    owner = record.x_owner_ids[:1]
    if not owner:
        raise UserError("No owner defined for this pet.")

    if not record.x_standard_package_ids:
        raise UserError("No products in Standard Package for this pet.")

    order_lines = []
    for product in record.x_standard_package_ids:
        order_lines.append((0, 0, {
            'product_id': product.id,
            'product_uom_qty': 1,
            'price_unit': product.lst_price,
        }))

    order = env['sale.order'].create({
        'partner_id': owner.id,
        'x_pet_ids': [(4, record.id)],
        'order_line': order_lines,
    })
    record['x_pets_sale_order_count'] = env['sale.order'].search_count([ ('x_pet_ids', 'in', [record.id])])
action = {
    'type': 'ir.actions.act_window',
    'res_model': 'sale.order',
    'res_id': order.id,
    'view_mode': 'form',
}

for order in records:
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Calendar Events',
        'res_model': 'calendar.event',
        'view_mode': 'list,form',
        'domain': [('x_sale_order_id', '=', order.id)],
        'context': {
            'default_x_sale_order_id': order.id,
            'default_x_pet_ids': [(6, 0, order.x_pet_ids.ids)],
        },
    }

for event in records:
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Sale Orders',
        'res_model': 'sale.order',
        'view_mode': 'list,form',
        'domain': [('x_calendar_event_ids', 'in', event.ids)],
        'context': {
            'default_x_calendar_event_ids': [(6, 0, event.ids)],
            'default_x_pet_ids': [(6, 0, event.x_pet_ids.ids)],
        },
    }
